  $('.banner-preview-section').insertAdjacentHTML('beforebegin',`<section class="form-field full banner-position-editor"><div class="banner-preview-head"><b>Enquadramento das imagens</b><span>Ajustes independentes</span></div><div class="banner-position-columns"><fieldset><legend>Computador</legend><label>Horizontal: <output id="banner-desktop-x-value">50%</output><input id="banner-desktop-x" type="range" min="0" max="100" value="50"></label><label>Vertical: <output id="banner-desktop-y-value">50%</output><input id="banner-desktop-y" type="range" min="0" max="100" value="50"></label><label>Zoom: <output id="banner-desktop-scale-value">100%</output><input id="banner-desktop-scale" type="range" min="10" max="400" value="100"></label><button class="btn ghost" type="button" data-banner-center="desktop">Centralizar computador</button></fieldset><fieldset><legend>Celular</legend><label>Horizontal: <output id="banner-mobile-x-value">50%</output><input id="banner-mobile-x" type="range" min="0" max="100" value="50"></label><label>Vertical: <output id="banner-mobile-y-value">50%</output><input id="banner-mobile-y" type="range" min="0" max="100" value="50"></label><label>Zoom: <output id="banner-mobile-scale-value">100%</output><input id="banner-mobile-scale" type="range" min="10" max="400" value="100"></label><button class="btn ghost" type="button" data-banner-center="mobile">Centralizar celular</button></fieldset></div><small>Use de 10% para bastante deszoom até 400% para aproximar. O preview usa exatamente o mesmo corte aplicado na home.</small></section>`);
  const bannerForm=$('#banner-form'),bannerPreview=$('.banner-preview-section'),bannerEditorFields=document.createElement('div');bannerEditorFields.className='banner-editor-fields';bannerForm.prepend(bannerEditorFields);[...bannerForm.children].filter(child=>child!==bannerEditorFields&&child!==bannerPreview).forEach(child=>bannerEditorFields.append(child));
  imageUploadHint('banner-desktop','<b>Ideal: 1640 × 380 px (4,32:1).</b> JPG, PNG, WebP ou GIF, até 8 MB. Deixe textos e produtos a pelo menos 50 px das bordas.');
  imageUploadHint('banner-mobile','<b>Ideal: 750 × 1000 px (3:4).</b> Até 8 MB, com o assunto centralizado. Sem esta imagem, a versão desktop será cortada para caber.');
  let rows=[],previewDesktop='',previewMobile='',previewHasSeparateMobile=false,previewObjectUrls=[];
  const bannerPreviewStyle=mobile=>{const prefix=mobile?'mobile':'desktop',x=$(`#banner-${prefix}-x`).value,y=$(`#banner-${prefix}-y`).value,scale=Number($(`#banner-${prefix}-scale`).value)/100;return `--preview-x:${x}%;--preview-y:${y}%;--preview-scale:${scale}`};
  const previewMarkup=(image,mobile=false)=>`<div class="home-banner ${mobile?'preview-mobile':''}" style="${bannerPreviewStyle(mobile)}"><img src="${esc(image||'')}" alt=""><span class="home-banner-shade"></span><span class="home-banner-copy"><small>${esc($('#banner-eyebrow').value)}</small><strong>${esc($('#banner-heading').value||'Título do banner')}</strong><span>${esc($('#banner-message').value||'Mensagem da promoção')}</span><b>${esc($('#banner-button').value||'Ver oferta')} →</b></span></div>`;
  const fitBannerPreviews=()=>{[['#banner-preview-desktop',1320,252],['#banner-preview-mobile',360,420]].forEach(([selector,width,height])=>{const host=$(selector),banner=host?.querySelector('.home-banner');if(!host||!banner)return;const fit=Math.min(1,host.clientWidth/width);banner.style.setProperty('--preview-fit',String(fit));host.style.height=`${height*fit}px`})};
  const renderBannerPreview=()=>{['desktop','mobile'].forEach(prefix=>{$(`#banner-${prefix}-x-value`).textContent=`${$(`#banner-${prefix}-x`).value}%`;$(`#banner-${prefix}-y-value`).textContent=`${$(`#banner-${prefix}-y`).value}%`;$(`#banner-${prefix}-scale-value`).textContent=`${$(`#banner-${prefix}-scale`).value}%`});$('#banner-preview-desktop').innerHTML=previewMarkup(previewDesktop);$('#banner-preview-mobile').innerHTML=previewMarkup(previewMobile||previewDesktop,true);requestAnimationFrame(fitBannerPreviews)};
  if('ResizeObserver'in window)new ResizeObserver(fitBannerPreviews).observe(bannerPreview);
